import{_ as s,o as a,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Use AWS KMS Signer","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Use AWS KMS Signer | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/operations/aws-kms-signer.md","filePath":"guides/operations/aws-kms-signer.md","lastUpdated":1774455097000}');const l=s({name:"guides/operations/aws-kms-signer.md"},[["render",function(s,o,l,p,t,r){return a(),n("div",null,[...o[0]||(o[0]=[e('<h1 id="use-aws-kms-signer" tabindex="-1">Use AWS KMS Signer <a class="header-anchor" href="#use-aws-kms-signer" aria-label="Permalink to &quot;Use AWS KMS Signer&quot;">​</a></h1><p>Use this guide to run <code>ev-node</code> with an AWS KMS-backed signer (<code>signer_type: kms</code>, <code>kms.provider: aws</code>) instead of a local key file.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>An AWS KMS <strong>asymmetric</strong> key with: <ul><li><code>KeyUsage: SIGN_VERIFY</code></li><li><code>KeySpec: ECC_NIST_EDWARDS25519</code></li></ul></li><li>IAM permissions for initial key creation/management (example policy):</li></ul><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">Version</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">2012-10-17</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">Statement</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> [</span></span>\n<span class="line"><span style="color:#767676;">    {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">Sid</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">AllowKeyCreation</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">Effect</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Allow</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">Action</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> [</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:CreateKey</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:TagResource</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:EnableKey</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:PutKeyPolicy</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:GetPublicKey</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:Sign</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:ListKeys</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#BFF3C280;">        &quot;</span><span style="color:#BFF3C2;">kms:ListAliases</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#767676;">      ],</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">Resource</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">*</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  ]</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><ul><li>Runtime IAM permissions for <code>ev-node</code> (minimum): <ul><li><code>kms:GetPublicKey</code></li><li><code>kms:Sign</code></li></ul></li><li>AWS credentials available to the node process (IAM role, env vars, or shared profile).</li></ul><h2 id="_1-create-an-ed25519-kms-key-example" tabindex="-1">1. Create an ED25519 KMS key (example) <a class="header-anchor" href="#_1-create-an-ed25519-kms-key-example" aria-label="Permalink to &quot;1. Create an ED25519 KMS key (example)&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">aws</span><span style="color:#BFF3C2;"> kms</span><span style="color:#BFF3C2;"> create-key</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --description</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">ev-node signer</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --key-usage</span><span style="color:#BFF3C2;"> SIGN_VERIFY</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --key-spec</span><span style="color:#BFF3C2;"> ECC_NIST_EDWARDS25519</span></span></code></pre></div><p>Copy the returned key ARN (or key ID). You can also create an alias and use that.</p><h2 id="_2-configure-evnode-yaml" tabindex="-1">2. Configure <code>evnode.yaml</code> <a class="header-anchor" href="#_2-configure-evnode-yaml" aria-label="Permalink to &quot;2. Configure `evnode.yaml`&quot;">​</a></h2><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">signer</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  signer_type</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">kms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  kms</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">    provider</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">aws</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">    aws</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">      key_id</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">arn:aws:kms:us-east-1:123456789012:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">      region</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">us-east-1</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">    # optional but recommended</span></span>\n<span class="line"><span style="color:#94EEFF;">      profile</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">prod</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">        # optional; omit when using IAM role/env creds</span></span>\n<span class="line"><span style="color:#94EEFF;">      timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">1s</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">         # must be &gt; 0</span></span>\n<span class="line"><span style="color:#94EEFF;">      max_retries</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 3</span><span style="color:#A0A0A0;">         # must be &gt;= 0</span></span></code></pre></div><h2 id="_3-start-as-an-aggregator" tabindex="-1">3. Start as an aggregator <a class="header-anchor" href="#_3-start-as-an-aggregator" aria-label="Permalink to &quot;3. Start as an aggregator&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.node.aggregator</span></span></code></pre></div><p>You should see a startup log line:</p><p><code>initialized AWS KMS signer via factory</code></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><code>evnode.signer.kms.aws.key_id is required when signer.signer_type is kms and signer.kms.provider is aws</code>: Set <code>signer.kms.aws.key_id</code>.</li><li><code>unsupported key type from KMS: expected ed25519</code>: Recreate the key as <code>ECC_NIST_EDWARDS25519</code>.</li><li><code>KMS Sign failed ...</code>: Check IAM permissions, key policy, region/profile, and network access to AWS KMS.</li></ul>',17)])])}]]);export{o as __pageData,l as default};
